validation_execution.code_example:
// Personオブジェクトに対してバリデーションを実行する必要があるため、
// Validアノテーションを設定する。
@POST
@Consumes(MediaType.APPLICATION_JSON)
@Valid
public HttpResponse save(Person person) {
    UniversalDao.insert(person);
    return new HttpResponse();
}

validation_group.code_example:
// Personクラス内に設定されているバリデーションルールのうち、
// Createグループに属するルールのみを使用してバリデーションを行う。
@POST
@Consumes(MediaType.APPLICATION_JSON)
@Valid
@ConvertGroup(from = Default.class, to = Create.class)
public HttpResponse save(Person person) {
    UniversalDao.insert(person);
    return new HttpResponse();
}
